const raw = $input.first().json.output;
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const parsed = JSON.parse(cleaned);

return [{
  json: {
    clasificacion: parsed.clasificacion,
    nombre: parsed.nombre,
    interes: parsed.interes,
    urgencia: parsed.urgencia,
    accion_recomendada: parsed.accion_recomendada,
    respuesta_automatica: parsed.respuesta_automatica
  }
}];

const d = $('Code in JavaScript').item.json;
const msg = $('Webhook').item.json.body.mensaje;

const html = `<div style="font-family: Arial, sans-serif; max-width: 620px; margin: 0 auto; background: #f7fafc; padding: 24px; border-radius: 8px;"><div style="background: white; border-radius: 8px; padding: 28px; box-shadow: 0 2px 8px rgba(0,0,0,0.08);"><h2 style="margin: 0 0 8px 0; color: #c53030; font-size: 22px;">🔥 Lead CALIENTE</h2><p style="margin: 0 0 24px 0; color: #718096; font-size: 14px;">Acción requerida — este lead quiere comprar pronto</p><table style="width: 100%; border-collapse: collapse; font-size: 15px;"><tr style="border-bottom: 1px solid #fed7d7;"><td style="padding: 14px 16px; font-weight: 700; color: #4a5568; width: 38%; background: #fff5f5;">Nombre</td><td style="padding: 14px 16px; color: #1a202c; background: #fff5f5;">${d.nombre}</td></tr><tr style="border-bottom: 1px solid #e2e8f0;"><td style="padding: 14px 16px; font-weight: 700; color: #4a5568;">Qué quiere</td><td style="padding: 14px 16px; color: #1a202c;">${d.interes}</td></tr><tr style="border-bottom: 1px solid #fed7d7;"><td style="padding: 14px 16px; font-weight: 700; color: #4a5568; background: #fff5f5;">Urgencia</td><td style="padding: 14px 16px; font-weight: 700; color: #c53030; background: #fff5f5;">${d.urgencia}</td></tr><tr style="border-bottom: 1px solid #e2e8f0;"><td style="padding: 14px 16px; font-weight: 700; color: #4a5568;">Acción recomendada</td><td style="padding: 14px 16px; color: #1a202c;">${d.accion_recomendada}</td></tr><tr><td style="padding: 14px 16px; font-weight: 700; color: #4a5568; background: #fffff0; vertical-align: top;">Mensaje original</td><td style="padding: 14px 16px; color: #718096; font-style: italic; background: #fffff0;">${msg}</td></tr></table><p style="margin: 24px 0 0 0; padding-top: 16px; border-top: 1px solid #e2e8f0; color: #a0aec0; font-size: 12px; text-align: center;">Generado automáticamente · Calificador de Leads n8n</p></div></div>`;

return [{ json: { ...d, htmlBody: html } }];

