const timestamp = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Mendoza' });

const html = `<div style="font-family: Arial, sans-serif; max-width: 620px; margin: 0 auto; padding: 24px;"><div style="background: white; border-radius: 8px; padding: 28px; border-left: 4px solid #e53e3e; box-shadow: 0 2px 8px rgba(0,0,0,0.08);"><h2 style="margin: 0 0 8px 0; color: #e53e3e;">⚠️ Error en Calificador de Leads</h2><p style="margin: 0 0 20px 0; color: #718096;">El workflow falló y necesita revisión</p><table style="width: 100%; border-collapse: collapse; font-size: 15px;"><tr style="border-bottom: 1px solid #fed7d7; background: #fff5f5;"><td style="padding: 12px 16px; font-weight: 700; color: #4a5568; width: 35%;">Nodo que falló</td><td style="padding: 12px 16px; color: #c53030; font-weight: 700;">${nodo}</td></tr><tr style="border-bottom: 1px solid #e2e8f0;"><td style="padding: 12px 16px; font-weight: 700; color: #4a5568;">Error</td><td style="padding: 12px 16px; color: #1a202c;">${mensaje}</td></tr><tr><td style="padding: 12px 16px; font-weight: 700; color: #4a5568; background: #f7fafc;">Timestamp</td><td style="padding: 12px 16px; color: #718096; background: #f7fafc;">${timestamp}</td></tr></table><p style="margin: 20px 0 0 0; color: #718096; font-size: 13px;">Revisá el workflow en <a href="http://localhost:5678" style="color: #3182ce;">localhost:5678</a></p></div></div>`;

return [{ json: { htmlError: html } }];
